function LineBreak() {
  return (
    <Box bgcolor="white">
      <br />
    </Box>
  );
}

function Introduction(props) {
  return (
    <Box bgcolor={colorPalette.dark} p={10} px={20}>
      <Typography align="center" variant="h3" color={colorPalette.text}>
        {props.aboutMe.name}
      </Typography>
      <br />
      <Typography align="center" variant="h4" color={colorPalette.text}>
        {props.aboutMe.shortDesc}
      </Typography>
      <br/>
      <Box sx={{display: "flex", justifyContent:"center"}}>
        <Button style={{backgroundColor: "white", maxWidth: '100px', maxHeight: '50px', minWidth: '100px', minHeight: '50px' }}>
          ONE
        </Button>
        <Button>TWO</Button>
      </Box>
    </Box>
  );
}

