import React from "react";
import Button from "@mui/material/Button";
import { Link } from "react-router-dom";
import {
  Box,
  Card,
  CardContent,
  Container,
  Grid,
  Typography,
} from "@mui/material";
import projectsData from "../../jsData/projectsData";
import ArrowForwardIosIcon from "@mui/icons-material/ArrowForwardIos";

const projectsPages = [
  {
    buttonName: "Type-Two",
    path: "/projects/type-two",
  },
];

function ProjectCard(props) {
  const project = props.project;
  return (
    <Grid container spacing={3}>
      <Grid item xs={6}>
        <img src={project.projectImage} width="300px" height="400px" border="1" />
      </Grid>
      <Grid item xs={6}>
        <Typography variant="h4">{project.projectName}</Typography>
        <Typography variant="h6">{project.projectDesc}</Typography>
        <br></br>
        <Button variant="contained" endIcon={<ArrowForwardIosIcon />}>
          View Details
        </Button>
      </Grid>
    </Grid>
  );
}

function Projects() {
  return (
    <div>
      <Container maxWidth="xl">
        <Grid container spacing={5}>
          <Grid item xs={6}>
            <ProjectCard project={projectsData[1]} />
          </Grid>
          <Grid item xs={6}>
            <ProjectCard project={projectsData[1]} />
          </Grid>
        </Grid>
      </Container>
    </div>
  );
}

export default Projects;
